import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtworkForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [formData, setFormData] = useState({
    Artwork_ID: '',
    Title_En: '',
    Artist_ID: '',
    Year: '',
    Cloudinary_Image1: '',
    Medium: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtworkById(id).then((res: any) => {
        setFormData(res.data);
      });
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtwork(formData);
      toast.success(id ? "Artwork Updated" : "Artwork Cataloged");
      navigate('/admin/artworks');
    } catch (err) { toast.error("Submission Failed"); }
    finally { setLoading(false); }
  };

  const handleExcelImport = async () => {
    if (!file) return toast.error("Select file");
    setLoading(true);
    try {
      await AdminService.importData('artwork', file);
      toast.success("Import Successful");
      navigate('/admin/artworks');
    } catch (err) { toast.error("Failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-6xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Back
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 bg-white dark:bg-[#0f0f0f] p-10 rounded-[3rem] border border-gray-100 dark:border-white/5">
          <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'Catalog'} <span className="text-primary">Artwork</span></h2>
          <form onSubmit={handleManualSubmit} className="grid grid-cols-2 gap-6">
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Artwork ID</label>
              <input value={formData.Artwork_ID} onChange={e => setFormData({...formData, Artwork_ID: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" placeholder="ART-001" required disabled={!!id} />
            </div>
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Artist ID</label>
              <input value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" placeholder="AR26" required />
            </div>
            <div className="col-span-2 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Title (EN)</label>
              <input value={formData.Title_En} onChange={e => setFormData({...formData, Title_En: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" required />
            </div>
            <div className="col-span-2 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Image URL</label>
              <input value={formData.Cloudinary_Image1} onChange={e => setFormData({...formData, Cloudinary_Image1: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" />
            </div>
            <button type="submit" className="col-span-2 bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-primary transition-all">Save Piece</button>
          </form>
        </div>

        {!id && (
          <div className="bg-white dark:bg-[#0f0f0f] p-8 rounded-[3rem] border border-gray-100 dark:border-white/5 h-fit">
            <h3 className="text-sm font-black uppercase italic mb-6">Bulk <span className="text-primary">Catalog</span></h3>
            <div className="border-2 border-dashed border-gray-100 dark:border-white/10 rounded-[2rem] p-10 text-center relative group">
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => setFile(e.target.files?.[0] || null)} />
              <Upload className="mx-auto text-gray-300 group-hover:text-primary mb-4" size={32} />
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{file ? file.name : 'Excel Upload'}</p>
            </div>
            <button onClick={handleExcelImport} className="w-full mt-6 bg-gray-50 dark:bg-white/5 py-4 rounded-2xl text-[10px] font-black uppercase hover:bg-black hover:text-white transition-all">Start Batch</button>
          </div>
        )}
      </div>
    </div>
  );
};
